#include <bits/stdc++.h>
using namespace std;
int main() {
    string s;
    cin >> s;
    int result = 0;
    unordered_map<char, int> roman_map = {{'I', 1}, {'V', 5}, {'X', 10}, {'L', 50}, {'C', 100}, {'D', 500}, {'M', 1000}};
    for (int i = 0; i < s.size(); i++) {
        if (i > 0 && roman_map[s[i]] > roman_map[s[i - 1]])
            result += roman_map[s[i]] - 2 * roman_map[s[i - 1]];
        else
            result += roman_map[s[i]];
    }
    cout << result;
}
